/* crdtLoanMapper.updateCrdtLoanInfoUsg */
UPDATE CLS_AGNCY_CRDT_LOAN_INFO
SET 
	CRDT_LOAN_USG_AMT = NVL(CRDT_LOAN_USG_AMT, 0) + #{CRDT_LOAN_AMT, jdbcType=NUMERIC}
	, CRDT_LOAN_BAL = NVL(CRDT_LOAN_BAL, 0) - #{CRDT_LOAN_AMT, jdbcType=NUMERIC}
	, RVISN_ID = #{USER_ID, jdbcType=VARCHAR}
	, RVISN_DTTM = SYSDATE
WHERE
	ORGN_ID = #{ORGN_ID, jdbcType=VARCHAR}
AND CRDT_LOAN_TYPE_CD = #{CRDT_LOAN_TYPE_CD, jdbcType=VARCHAR}

