/* crdtLoanMapper.setCrdtLoanInit */
UPDATE CLS_AGNCY_CRDT_LOAN_INFO
SET

		/*일반여신금액*/
		GNRL_CRDT_LOAN_AMT = NVL(GNRL_CRDT_LOAN_AMT, 0) - #{CRDT_LOAN_STUP_AMT, jdbcType=NUMERIC}


		/*특별여신금액*/
		SPCL_CRDT_LOAN_AMT = NVL(SPCL_CRDT_LOAN_AMT, 0) - #{CRDT_LOAN_STUP_AMT, jdbcType=NUMERIC}

	, CRDT_LOAN_BAL = NVL(CRDT_LOAN_BAL, 0) - #{CRDT_LOAN_STUP_AMT, jdbcType=NUMERIC}
	, RVISN_ID = #{USER_ID, jdbcType=VARCHAR}
	, RVISN_DTTM = SYSDATE
WHERE
	ORGN_ID = #{ORGN_ID, jdbcType=VARCHAR}
	AND CRDT_LOAN_TYPE_CD = #{CRDT_LOAN_TYPE_CD, jdbcType=VARCHAR}
